#ifndef PROTOCOL_H
#define PROTOCOL_H

#include <stdbool.h>
#include <stddef.h>

#define PROTOCOL_MAX_LINE_LENGTH 128

typedef enum {
    PROTOCOL_INPUT_NONE = 0,
    PROTOCOL_INPUT_TURBIDITY,
    PROTOCOL_INPUT_LEVEL,
    PROTOCOL_INPUT_SENSOR_TIMEOUT,
    PROTOCOL_INPUT_INVALID_TURBIDITY,
    PROTOCOL_INPUT_INVALID_LEVEL,
} protocol_input_kind_t;

typedef struct {
    protocol_input_kind_t kind;
    int turbidity_ntu;
    int level;
} protocol_input_t;

typedef enum {
    PROTOCOL_PARSE_IGNORED = 0,
    PROTOCOL_PARSE_TURBIDITY,
    PROTOCOL_PARSE_LEVEL,
    PROTOCOL_PARSE_SENSOR_TIMEOUT,
    PROTOCOL_PARSE_INVALID_TURBIDITY,
    PROTOCOL_PARSE_INVALID_LEVEL,
} protocol_parse_result_t;

protocol_parse_result_t protocol_parse_line(const char *line, protocol_input_t *input);
bool protocol_serialize_act_filter(bool filter_on, char *buffer, size_t buffer_size);
bool protocol_serialize_act_drain(bool drain_open, char *buffer, size_t buffer_size);
bool protocol_serialize_debug(const char *message, char *buffer, size_t buffer_size);

#endif

#include "protocol.h"

#include <ctype.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

static void protocol_reset_input(protocol_input_t *input)
{
    if (input == NULL) {
        return;
    }

    input->kind = PROTOCOL_INPUT_NONE;
    input->turbidity_ntu = 0;
    input->level = 0;
}

static void protocol_trim_copy(const char *line, char *buffer, size_t buffer_size)
{
    size_t source_length;
    size_t start = 0U;
    size_t end;
    size_t length;

    if (buffer_size == 0U) {
        return;
    }

    buffer[0] = '\0';
    if (line == NULL) {
        return;
    }

    source_length = strnlen(line, buffer_size - 1U);
    while ((start < source_length) && isspace((unsigned char) line[start])) {
        start++;
    }

    end = source_length;
    while ((end > start) && isspace((unsigned char) line[end - 1U])) {
        end--;
    }

    length = end - start;
    memcpy(buffer, line + start, length);
    buffer[length] = '\0';
}

static bool protocol_parse_turbidity_value(const char *token, int *turbidity_ntu)
{
    char *end = NULL;
    long parsed;

    if ((token == NULL) || (turbidity_ntu == NULL)) {
        return false;
    }

    parsed = strtol(token, &end, 10);
    if ((end == token) || (*end != '\0')) {
        return false;
    }

    if ((parsed < 0L) || (parsed > 100L)) {
        return false;
    }

    *turbidity_ntu = (int) parsed;
    return true;
}

static bool protocol_parse_level_value(const char *token, int *level)
{
    char *end = NULL;
    long parsed;

    if ((token == NULL) || (level == NULL)) {
        return false;
    }

    parsed = strtol(token, &end, 10);
    if ((end == token) || (*end != '\0')) {
        return false;
    }

    if ((parsed < 0L) || (parsed > 100L)) {
        return false;
    }

    *level = (int) parsed;
    return true;
}

protocol_parse_result_t protocol_parse_line(const char *line, protocol_input_t *input)
{
    char scratch[PROTOCOL_MAX_LINE_LENGTH];
    char *save = NULL;
    char *first;
    char *second;
    char *third;
    char *fourth;
    int value;

    protocol_reset_input(input);
    protocol_trim_copy(line, scratch, sizeof(scratch));
    if (scratch[0] == '\0') {
        return PROTOCOL_PARSE_IGNORED;
    }

    first = strtok_r(scratch, " \t", &save);
    second = strtok_r(NULL, " \t", &save);
    third = strtok_r(NULL, " \t", &save);
    fourth = strtok_r(NULL, " \t", &save);

    if ((first != NULL) && (second != NULL) && (strcmp(first, "SENSE") == 0) && (strcmp(second, "TURB") == 0)) {
        if ((third == NULL) || (fourth != NULL) || !protocol_parse_turbidity_value(third, &value)) {
            if (input != NULL) {
                input->kind = PROTOCOL_INPUT_INVALID_TURBIDITY;
            }
            return PROTOCOL_PARSE_INVALID_TURBIDITY;
        }

        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_TURBIDITY;
            input->turbidity_ntu = value;
        }
        return PROTOCOL_PARSE_TURBIDITY;
    }

    if ((first != NULL) && (second != NULL) && (strcmp(first, "SENSE") == 0) && (strcmp(second, "LEVEL") == 0)) {
        if ((third == NULL) || (fourth != NULL) || !protocol_parse_level_value(third, &value)) {
            if (input != NULL) {
                input->kind = PROTOCOL_INPUT_INVALID_LEVEL;
            }
            return PROTOCOL_PARSE_INVALID_LEVEL;
        }

        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_LEVEL;
            input->level = value;
        }
        return PROTOCOL_PARSE_LEVEL;
    }

    if ((first != NULL) && (second != NULL) && (strcmp(first, "FAULT") == 0) && (strcmp(second, "SENSOR_TIMEOUT") == 0) && (third == NULL)) {
        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_SENSOR_TIMEOUT;
        }
        return PROTOCOL_PARSE_SENSOR_TIMEOUT;
    }

    return PROTOCOL_PARSE_IGNORED;
}

bool protocol_serialize_act_filter(bool filter_on, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "ACT FILTER %s\n", filter_on ? "ON" : "OFF");
    return (written >= 0) && ((size_t) written < buffer_size);
}

bool protocol_serialize_act_drain(bool drain_open, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "ACT DRAIN %s\n", drain_open ? "OPEN" : "CLOSED");
    return (written >= 0) && ((size_t) written < buffer_size);
}

bool protocol_serialize_debug(const char *message, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "DBG %s\n", message != NULL ? message : "");
    return (written >= 0) && ((size_t) written < buffer_size);
}

#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Check for sensor timeout - if either sensor is stale for > 1000ms, go to safe idle */
    bool sensor_timeout = false;
    if (controller->has_valid_turbidity && controller->last_turbidity_ms == 0U) {
        sensor_timeout = true;
    } else if (controller->has_valid_level && controller->last_level_ms == 0U) {
        sensor_timeout = true;
    }

    /* Handle different input types */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        /* Turbidity input - check for stale data */
        if (controller->last_turbidity_ms == 0U || controller->last_turbidity_ms < input.now_ms - CONTROLLER_SENSOR_TIMEOUT_MS) {
            sensor_timeout = true;
        } else {
            /* Valid turbidity input */
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = input.now_ms;

            /* Update clear streak based on turbidity level */
            if (controller->state != CONTROLLER_STATE_SETTLING && controller->state != CONTROLLER_STATE_DRAINING) {
                if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->clear_streak_count++;
                } else {
                    controller->clear_streak_count = 0;
                }
            }
        }
        break;

    case CONTROLLER_INPUT_LEVEL:
        /* Level input - check for stale data */
        if (controller->last_level_ms == 0U || controller->last_level_ms < input.now_ms - CONTROLLER_SENSOR_TIMEOUT_MS) {
            sensor_timeout = true;
        } else {
            /* Valid level input */
            controller->has_valid_level = true;
            controller->last_level = input.level;
            controller->last_level_ms = input.now_ms;
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit sensor timeout - force safe state */
        sensor_timeout = true;
        break;

    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Malformed input - force safe state */
        sensor_timeout = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No input or unknown - stay in current state but check timeouts */
        break;
    }

    /* If there's a sensor timeout, go to safe idle */
    if (sensor_timeout) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
    } else {
        /* Process the state machine based on current state and inputs */
        int current_level = controller->has_valid_level ? controller->last_level : 0;
        int current_turbidity = controller->has_valid_turbidity ? controller->last_turbidity_ntu : 0;

        /* COMPLETE state: level < 15, stay in COMPLETE */
        if (current_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            output.filter_on = false;
            output.drain_open = false;
            output.state_name = controller_state_name(CONTROLLER_STATE_COMPLETE);
        }
        /* SAFE_IDLE state: both sensors valid but no other conditions met */
        else if (!controller->has_valid_turbidity || !controller->has_valid_level) {
            /* Wait for both sensors to be valid */
            controller->state = CONTROLLER_STATE_SAFE_IDLE;
            output.filter_on = false;
            output.drain_open = false;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        }
        /* FILTERING state: TURB > 35 and LEVEL >= 40 */
        else if (current_turbidity > CONTROLLER_CLEAR_THRESHOLD_NTU && current_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->state = CONTROLLER_STATE_FILTERING;
            output.filter_on = true;
            output.drain_open = false;
            output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
        }
        /* SETTLING state: clear streak >= 3, LEVEL >= 40 */
        else if (controller->state == CONTROLLER_STATE_SAFE_IDLE &&
                 current_turbidity <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
                 current_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
                 controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
            controller->state = CONTROLLER_STATE_SETTLING;
            output.filter_on = false;
            output.drain_open = false;
            output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
            controller->settling_started_ms = input.now_ms;
        }
        /* DRAINING state: settling duration >= 400ms, latest TURB <= 35, LEVEL >= 40 */
        else if (controller->state == CONTROLLER_STATE_SETTLING &&
                 controller->has_valid_turbidity &&
                 current_turbidity <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
                 current_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            uint32_t settling_duration = input.now_ms - controller->settling_started_ms;
            if (settling_duration >= CONTROLLER_SETTLING_MS) {
                controller->state = CONTROLLER_STATE_DRAINING;
                output.filter_on = false;
                output.drain_open = true;
                output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
            } else {
                /* Still in SETTLING */
                output.filter_on = false;
                output.drain_open = false;
                output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
            }
        }
        /* DRAINING state: TURB > 50 and LEVEL >= 40, close drain, restart filtering */
        else if (controller->state == CONTROLLER_STATE_DRAINING &&
                 current_turbidity > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                 current_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->state = CONTROLLER_STATE_FILTERING;
            output.filter_on = true;
            output.drain_open = false;
            output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
            controller->clear_streak_count = 0;
        }
        /* Other states - maintain current state with appropriate outputs */
        else {
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state_name = controller_state_name(controller->state);
        }

        output.changed =
            (previous_filter_on != output.filter_on) ||
            (previous_drain_open != output.drain_open) ||
            (previous_state != controller->state);
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != output.filter_on) ||
        (previous_drain_open != output.drain_open) ||
        (previous_state != controller->state);
    return output;
}

