    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        /* Turbidity input - check for stale data only if we already have a valid value */
        bool clear_streak_was_in_settling_or_draining = false;
        if (controller->has_valid_turbidity && controller->last_turbidity_ms < input.now_ms - CONTROLLER_SENSOR_TIMEOUT_MS) {
            sensor_timeout = true;
        } else {
            /* Valid turbidity input */
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = input.now_ms;

            /* Check if we were in a state that would prevent clear streak increment */
            clear_streak_was_in_settling_or_draining = (controller->state == CONTROLLER_STATE_SETTLING || controller->state == CONTROLLER_STATE_DRAINING);

            /* Update clear streak based on turbidity level */
            if (!clear_streak_was_in_settling_or_draining) {
                if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->clear_streak_count++;
                } else {
                    controller->clear_streak_count = 0;
                }
            }
        }
        break;

    case CONTROLLER_INPUT_LEVEL:
        /* Level input - check for stale data only if we already have a valid value */
        if (controller->has_valid_level && controller->last_level_ms < input.now_ms - CONTROLLER_SENSOR_TIMEOUT_MS) {
            sensor_timeout = true;
        } else {
            /* Valid level input */
            controller->has_valid_level = true;
            controller->last_level = input.level;
            controller->last_level_ms = input.now_ms;
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit sensor timeout - force safe state */
        sensor_timeout = true;
        break;

    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Malformed input - force safe state */
        sensor_timeout = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No input or unknown - stay in current state but check timeouts */
        break;
    }

