            controller->filter_on = false;
            controller->drain_open = false;
            output.filter_on = false;
            output.drain_open = false;
            output.state_name = controller_state_name(CONTROLLER_STATE_COMPLETE);
        }
        /* SAFE_IDLE state: both sensors valid but no other conditions met */
        else if (!controller->has_valid_turbidity || !controller->has_valid_level) {
